package unverified;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair4492DifferenceFindingTest {

    private final ClonePair4492 subject = new ClonePair4492();

    /**
     * Generated by Codex (GPT-5.5).
     */
    @Test
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{new double[]{1.0, Double.NaN}};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((double[]) values[0]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((double[]) values[0]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(1.0)",
            null,
            "java.lang.Object[][double[][1.0, NaN]]",
            "java.lang.Object[][double[][1.0, NaN]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(NaN)",
            null,
            "java.lang.Object[][double[][1.0, NaN]]",
            "java.lang.Object[][double[][1.0, NaN]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
